/* Blog Page Styles */

.blog-hero {
    padding: 120px 20px 60px;
    background: var(--theme-secondary);
    color: var(--theme-white);
    text-align: center;
}

.blog-hero h1 {
    font-size: 3rem;
    margin-bottom: 20px;
}

.blog-hero p {
    font-size: 1.2rem;
    opacity: 0.9;
    max-width: 700px;
    margin: 0 auto;
}

.blog-container {
    max-width: 1200px;
    margin: 40px auto;
    padding: 0 20px;
}

.blog-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(350px, 1fr));
    gap: 40px;
}

.blog-card {
    background: var(--theme-white);
    border-radius: 15px;
    overflow: hidden;
    box-shadow: 0 10px 30px var(--theme-shadow);
    transition: transform 0.3s ease, box-shadow 0.3s ease;
    display: flex;
    flex-direction: column;
}

.blog-card:hover {
    transform: translateY(-10px);
    box-shadow: 0 15px 40px var(--theme-shadow-dark);
}

.blog-card-image {
    height: 250px;
    overflow: hidden;
}

.blog-card-image img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    transition: transform 0.5s ease;
}

.blog-card:hover .blog-card-image img {
    transform: scale(1.1);
}

.blog-card-content {
    padding: 25px;
    flex-grow: 1;
    display: flex;
    flex-direction: column;
}

.blog-card-tag {
    display: inline-block;
    padding: 5px 15px;
    background: var(--theme-primary);
    color: var(--theme-white);
    border-radius: 50px;
    font-size: 0.8rem;
    font-weight: 600;
    margin-bottom: 15px;
    align-self: flex-start; /* Prevent stretching after adding flexbox to container */
}

.blog-card-title {
    font-size: 1.5rem;
    color: var(--theme-secondary);
    margin-bottom: 15px;
    line-height: 1.3;
}

.blog-card-excerpt {
    color: #666;
    line-height: 1.6;
    margin-bottom: 20px;
}

.blog-card-link {
    display: flex;
    align-items: center;
    color: var(--theme-primary);
    text-decoration: none;
    font-weight: 700;
    gap: 10px;
    margin-top: auto; /* Push button to the bottom */
}

.blog-card-link i {
    transition: transform 0.3s ease;
}

.blog-card-link:hover i {
    transform: translateX(5px);
}

@media (max-width: 768px) {
    .blog-hero h1 {
        font-size: 2.2rem;
    }

    .blog-grid {
        grid-template-columns: 1fr;
    }

    .blog-container {
        margin: 40px auto;
    }
}

/* Main Article Design Improvements */
.article-container {
    max-width: 900px;
    margin: 80px auto;
    padding: 0 25px;
}

.back-to-blog {
    display: inline-flex;
    align-items: center;
    gap: 10px;
    text-decoration: none;
    color: var(--theme-primary); /* Orange color requested */
    font-weight: 600;
    margin-bottom: 30px;
    transition: transform 0.3s ease;
}

.back-to-blog:hover {
    transform: translateX(-5px);
}

.back-to-blog i {
    font-size: 0.9rem;
}

.article-header {
    margin-bottom: 50px;
    text-align: center;
}

.article-meta {
    display: flex;
    justify-content: center;
    gap: 30px;
    color: var(--theme-text-muted);
    font-size: 0.95rem;
    margin-bottom: 25px;
    font-weight: 500;
}

.article-meta i {
    color: var(--theme-primary);
    margin-right: 8px;
}

.article-title {
    font-size: 3.2rem;
    color: var(--theme-secondary);
    line-height: 1.1;
    margin-bottom: 30px;
    font-weight: 800;
}

@media (max-width: 768px) {
    .article-title {
        font-size: 2.2rem;
    }
}

.article-hero-image {
    width: 100%;
    height: 500px;
    border-radius: 20px;
    overflow: hidden;
    margin-bottom: 60px;
    box-shadow: 0 20px 40px var(--theme-shadow-dark);
}

.article-hero-image img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.article-content {
    color: var(--theme-text-main);
    line-height: 1.9;
    font-size: 1.15rem;
}

.article-content h2 {
    color: var(--theme-secondary);
    margin: 60px 0 25px;
    font-size: 2.2rem;
    font-weight: 700;
    position: relative;
    padding-bottom: 15px;
}

.article-content h2::after {
    content: '';
    position: absolute;
    bottom: 0;
    left: 0;
    width: 60px;
    height: 4px;
    background: var(--theme-primary);
    border-radius: 2px;
}

.article-content p {
    margin-bottom: 25px;
}

/* Pro Tip Box */
.pro-tip {
    background: var(--theme-bg-blue-light);
    border-left: 5px solid var(--theme-primary);
    padding: 30px;
    border-radius: 0 15px 15px 0;
    margin: 40px 0;
    display: flex;
    gap: 20px;
}

.pro-tip-icon {
    font-size: 2rem;
    color: var(--theme-primary);
}

.pro-tip-content h4 {
    margin: 0 0 10px;
    color: var(--theme-secondary);
    font-size: 1.3rem;
}

.pro-tip-content p {
    margin: 0;
    font-size: 1.05rem;
    color: #444;
}

/* Article Checklist */
.article-checklist {
    background: var(--theme-bg-gray);
    padding: 35px;
    border-radius: 20px;
    margin: 50px 0;
}

.article-checklist h3 {
    margin-top: 0;
    color: var(--theme-secondary);
    margin-bottom: 25px;
}

.article-checklist ul {
    list-style: none !important;
    padding: 0 !important;
}

.article-checklist li {
    display: flex;
    align-items: flex-start;
    gap: 15px;
    margin-bottom: 15px !important;
    font-weight: 500;
}

.article-checklist li i {
    color: var(--theme-success);
    margin-top: 5px;
}

/* Internal Links / CTA */
.article-cta-box {
    background: var(--theme-secondary);
    color: var(--theme-white);
    padding: 45px;
    border-radius: 25px;
    text-align: center;
    margin: 60px 0;
}

.article-cta-box h3 {
    font-size: 1.8rem;
    margin-bottom: 15px;
}

.article-cta-box p {
    margin-bottom: 30px;
    opacity: 0.9;
}

.cta-button {
    display: inline-block;
    background: #FF6600;
    color: white;
    padding: 15px 40px;
    border-radius: 50px;
    text-decoration: none;
    font-weight: 700;
    transition: all 0.3s ease;
    box-shadow: 0 10px 20px var(--theme-shadow-dark);
}

.cta-button:hover {
    transform: translateY(-5px);
    background: var(--theme-primary-hover);
    box-shadow: 0 15px 30px var(--theme-shadow-dark);
}

/* Social Share */
.social-share {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 20px;
    margin-top: 60px;
    padding-top: 40px;
    border-top: 1px solid var(--theme-border-light);
}

.social-share span {
    font-weight: 600;
    color: #666;
}

.share-btn {
    width: 45px;
    height: 45px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    background: var(--theme-bg-gray);
    color: var(--theme-secondary);
    text-decoration: none;
    transition: all 0.3s ease;
}

.share-btn:hover {
    background: #FF6600;
    color: white;
}

@media (max-width: 768px) {
    .article-hero-image {
        height: 250px;
        margin-bottom: 30px;
    }

    .article-content {
        font-size: 1.05rem;
    }

    .article-content h2 {
        font-size: 1.8rem;
        margin: 40px 0 20px;
    }

    .pro-tip {
        flex-direction: column;
        padding: 20px;
        gap: 15px;
    }

    .article-checklist {
        padding: 25px 20px;
        margin: 30px 0;
    }

    .article-checklist li {
        font-size: 1rem;
    }

    .article-cta-box {
        padding: 35px 20px;
        margin: 40px 0;
    }

    .article-cta-box h3 {
        font-size: 1.5rem;
    }
}

/* Nouvelles utilités */
.lead {
    font-size: 1.4rem;
    color: #4A5568;
    line-height: 1.6;
    font-weight: 500;
    margin-bottom: 40px !important;
}

.fade-in {
    opacity: 0;
    transform: translateY(30px);
    transition: all 0.8s cubic-bezier(0.4, 0, 0.2, 1);
}

.fade-in.visible {
    opacity: 1;
    transform: translateY(0);
}

files.city-page.css:
/* ============================================
   CITY PAGE SHARED CORE STYLES
   ============================================ */

.city-hero {
    height: 75vh;
    min-height: 600px;
    background: linear-gradient(var(--theme-overlay-dark), var(--theme-overlay-dark)), url('image/Renovation-toiture-1.jpg');
    background-size: cover;
    background-position: center;
    background-attachment: fixed;
    display: flex;
    align-items: center;
    justify-content: center;
    text-align: center;
    color: var(--theme-white);
    padding: 0 20px;
    position: relative;
    overflow: hidden;
}

.city-hero::after {
    content: '';
    position: absolute;
    bottom: -5px;
    left: 0;
    width: 100%;
    height: 100px;
    background: var(--theme-white);
    clip-path: ellipse(55% 60% at 50% 100%);
    z-index: 2;
}

.city-hero-content {
    max-width: 900px;
    z-index: 3;
    padding-bottom: 50px;
    padding-top: 100px; /* Reduced from 120px */
}

.city-label {
    display: inline-block;
    background: var(--theme-bg-light);
    border: 1px solid var(--theme-primary);
    color: var(--theme-primary);
    padding: 8px 20px;
    border-radius: 50px;
    font-weight: 600;
    margin-bottom: 20px;
    text-transform: uppercase;
    font-size: 0.9rem;
    letter-spacing: 1px;
    backdrop-filter: blur(5px);
}

.city-hero-title {
    font-size: 3.5rem;
    font-weight: 800;
    margin-bottom: 15px;
    line-height: 1.2;
    text-shadow: 0 4px 10px var(--theme-shadow-dark);
}

.city-hero-subtitle {
    font-size: 1.4rem;
    font-weight: 300;
    opacity: 0.9;
    margin-bottom: 40px;
    max-width: 700px;
    margin-left: auto;
    margin-right: auto;
}

.city-hero-buttons {
    display: flex;
    gap: 20px;
    justify-content: center;
}

.city-cta-button {
    padding: 15px 35px;
    border-radius: 50px;
    font-weight: 600;
    text-decoration: none;
    transition: all 0.3s ease;
    font-size: 1rem;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.city-cta-button.primary {
    background: var(--theme-primary);
    color: var(--theme-white);
    box-shadow: 0 10px 25px var(--theme-shadow-dark);
}

.city-cta-button.primary:hover {
    background: #e65c00;
    transform: translateY(-3px);
    box-shadow: 0 15px 35px rgba(255, 102, 0, 0.4);
}

.city-cta-button.secondary {
    background: transparent;
    border: 2px solid var(--theme-white);
    color: var(--theme-white);
}

.city-cta-button.secondary:hover {
    background: var(--theme-white);
    color: var(--theme-secondary);
    transform: translateY(-3px);
}

/* Call to Action Form */
.city-cta-section {
    padding: 80px 20px;
    background: var(--theme-secondary);
    color: var(--theme-white);
    text-align: center;
    border: none !important;
    margin-bottom: 0 !important;
}

.city-cta-container {
    max-width: 800px;
    margin: 0 auto;
}

.city-cta-container h2 {
    font-size: 2.5rem;
    margin-bottom: 15px;
}

.city-cta-container p {
    font-size: 1.2rem;
    opacity: 0.8;
    margin-bottom: 40px;
}

.city-contact-form {
    background: var(--theme-white);
    padding: 40px;
    border-radius: 20px;
    box-shadow: 0 20px 60px var(--theme-shadow-dark);
    display: flex;
    flex-direction: column;
    gap: 20px;
}

.form-row {
    display: flex;
    gap: 20px;
}

.city-contact-form input,
.city-contact-form textarea {
    padding: 15px 20px;
    border: 2px solid var(--theme-border);
    border-radius: 10px;
    font-family: inherit;
    font-size: 1rem;
    outline: none;
    transition: border-color 0.3s;
}

.city-contact-form input:focus,
.city-contact-form textarea:focus {
    border-color: var(--theme-primary);
}

.form-row input {
    flex: 1;
}

.city-contact-form button {
    background: #FF6600;
    color: #ffffff;
    font-size: 1.1rem;
    font-weight: 700;
    padding: 18px;
    border: none;
    border-radius: 10px;
    cursor: pointer;
    transition: all 0.3s;
    text-transform: uppercase;
    letter-spacing: 1px;
}

.city-contact-form button:hover {
    background: #e65c00;
    transform: translateY(-2px);
    box-shadow: 0 10px 20px rgba(0, 0, 0, 0.1);
}

/* ============================================
   NEW CLEAN TEXT LAYOUT
   ============================================ */

.city-main-content {
    padding: 100px 20px;
    background: #ffffff;
}

.city-content-container {
    max-width: 1100px;
    margin: 0 auto;
}

.city-article-header {
    text-align: center;
    margin-bottom: 80px;
}

.city-article-header h2 {
    font-size: 3rem;
    color: #0A2342;
    margin-bottom: 20px;
    font-weight: 800;
}

.city-article-header .divider {
    width: 80px;
    height: 4px;
    background: #FF6600;
    margin: 0 auto;
    border-radius: 2px;
}

.city-text-grid {
    display: grid;
    grid-template-columns: 1.4fr 1fr;
    gap: 100px;
    margin-bottom: 120px;
    align-items: center;
}

.city-text-grid.reverse {
    grid-template-columns: 1fr 1.4fr;
}

.city-text-block {
    display: flex;
    flex-direction: column;
    gap: 30px;
}

.city-text-block h3 {
    font-size: 2.2rem;
    color: #0A2342;
    margin-bottom: 15px;
    font-weight: 700;
}

.city-text-block p {
    font-size: 1.15rem;
    line-height: 1.9;
    color: var(--theme-text-muted);
    margin: 0;
}

.city-deco-image-wrapper {
    position: relative;
    padding: 20px;
}

.city-deco-image-wrapper img {
    width: 100%;
    height: 550px;
    object-fit: cover;
    border-radius: 30px;
    box-shadow: 0 40px 80px rgba(0, 0, 0, 0.15);
}

.city-features-text {
    background: #f8fafc;
    padding: 80px 60px;
    border-radius: 40px;
    margin-top: 80px;
}

.city-features-text h3 {
    text-align: center;
    margin-bottom: 60px;
    font-size: 2.5rem;
}

.features-list-clean {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 50px;
    list-style: none;
    padding: 0;
}

.feature-item-clean {
    display: flex;
    gap: 25px;
    align-items: flex-start;
}

.feature-item-clean i {
    font-size: 1.8rem;
    color: #FF6600;
    margin-top: 5px;
    background: #FFF4EC;
    width: 60px;
    height: 60px;
    display: flex;
    align-items: center;
    justify-content: center;
    border-radius: 15px;
    flex-shrink: 0;
}

.feature-content h4 {
    font-size: 1.4rem;
    color: #0A2342;
    margin-bottom: 12px;
}

.feature-content p {
    color: var(--theme-text-light);
    line-height: 1.7;
    font-size: 1.05rem;
}

/* Responsive adjustments */
@media (max-width: 992px) {
    .city-hero-title {
        font-size: 2.5rem;
    }

    .city-text-grid,
    .city-text-grid.reverse {
        grid-template-columns: 1fr;
        gap: 60px;
    }

    .city-deco-image-wrapper img {
        height: 450px;
    }

    .features-list-clean {
        grid-template-columns: 1fr;
    }
}

@media (max-width: 768px) {
    .city-article-header h2 {
        font-size: 2.2rem;
    }

    .city-main-content {
        padding: 60px 20px;
    }

    .city-features-text {
        padding: 40px 25px;
    }

    .city-hero {
        height: auto;
        min-height: auto;
        padding: 80px 20px 60px;
    }

    .city-hero-content {
        padding-top: 60px;
    }
}

