// Script pour charger les composants réutilisables (navbar et footer) 
// et initialiser les services globaux (EmailJS, Dynamic Colors)

// Injecter color.js dynamiquement s'il n'est pas déjà présent
if (!document.querySelector('script[src*="color.js"]')) {
    const colorScript = document.createElement('script');
    colorScript.src = 'color.js';
    document.head.prepend(colorScript);
}

document.addEventListener('DOMContentLoaded', function() {
    // Charger la navbar
    const navbarPlaceholder = document.getElementById('navbar-placeholder');
    if (navbarPlaceholder) {
        fetch('navbar.html')
            .then(response => response.text())
            .then(data => {
                navbarPlaceholder.innerHTML = data;
                initNavbar(); // Initialiser la logique de la navbar après le chargement
            })
            .catch(error => console.error('Erreur lors du chargement de la navbar:', error));
    }

    // Charger le footer
    const footerPlaceholder = document.getElementById('footer-placeholder');
    if (footerPlaceholder) {
        fetch('footer.html')
            .then(response => response.text())
            .then(data => {
                footerPlaceholder.innerHTML = data;
            })
            .catch(error => console.error('Erreur lors du chargement du footer:', error));
    }

    // Charger les services tiers (EmailJS)
    const emailjsScript = document.createElement('script');
    emailjsScript.src = 'https://cdn.jsdelivr.net/npm/@emailjs/browser@3/dist/email.min.js';
    emailjsScript.onload = function() {
        // Une fois EmailJS chargé, on charge notre script de configuration
        const customEmailScript = document.createElement('script');
        customEmailScript.src = 'email.js';
        document.body.appendChild(customEmailScript);
    };
    document.body.appendChild(emailjsScript);
});

function initNavbar() {
    const navToggle = document.getElementById('nav-toggle');
    const navMenu = document.getElementById('nav-menu');
    const navbar = document.querySelector('.navbar');

    if (!navToggle || !navMenu) return;

    function closeMenu() {
        navMenu.classList.remove('active');
        navToggle.classList.remove('active');
    }

    function openMenu() {
        navMenu.classList.add('active');
        navToggle.classList.add('active');
    }

    navToggle.addEventListener('click', function (e) {
        e.stopPropagation();
        if (navMenu.classList.contains('active')) {
            closeMenu();
        } else {
            openMenu();
        }
    });

    // Mobile Dropdown Toggle
    const dropdowns = document.querySelectorAll('.dropdown');
    dropdowns.forEach(dropdown => {
        const toggle = dropdown.querySelector('.dropdown-toggle');
        if (toggle) {
            toggle.addEventListener('click', function (e) {
                e.preventDefault();
                e.stopPropagation();

                // Close other dropdowns
                dropdowns.forEach(d => {
                    if (d !== dropdown) d.classList.remove('active');
                });

                dropdown.classList.toggle('active');
            });
        }
    });

    // Close menu when clicking on a link
    const navLinks = document.querySelectorAll('.nav-link');
    navLinks.forEach(link => {
        link.addEventListener('click', function (e) {
            if (!link.classList.contains('dropdown-toggle')) {
                closeMenu();
            }
        });
    });

    // Close menu when clicking outside
    document.addEventListener('click', function (e) {
        if (navMenu.classList.contains('active') &&
            !navMenu.contains(e.target) &&
            !navToggle.contains(e.target)) {
            closeMenu();
        }
    });

    // Highlight active navigation link
    const currentPage = window.location.pathname.split('/').pop() || 'index.html';
    navLinks.forEach(link => {
        const linkPage = link.getAttribute('href');
        if (linkPage === currentPage) {
            link.classList.add('active');
        }
    });

    // Navbar scroll animation
    let lastScrollTop = 0;
    window.addEventListener('scroll', function () {
        const scrollTop = window.pageYOffset || document.documentElement.scrollTop;

        if (scrollTop > lastScrollTop && scrollTop > 100) {
            navbar.classList.add('hidden');
        } else {
            navbar.classList.remove('hidden');
        }
        lastScrollTop = scrollTop;
    }, { passive: true });
}

