    /* Smooth transition for hidden state */
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif !important;
}

.navbar.hidden {
    transform: translateY(-100%);
}

.nav-container {
    max-width: 100%;
    margin: 0 auto;
    padding: 12px 20px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    position: relative;
    z-index: 10013;
    background: var(--theme-nav-bg);
}

.nav-left {
    display: flex;
    align-items: center;
    gap: 25px;
}

.nav-logo {
    font-size: 1.6rem;
    font-weight: 700;
    color: var(--theme-nav-text);
    position: relative;
    z-index: 10014;
}

.logo-link {
    color: var(--theme-nav-text);
    text-decoration: none;
    transition: color 0.3s;
}

.logo-link:hover {
    color: var(--theme-primary);
}

/* Badges style pill */
.nav-badges {
    display: flex;
    gap: 12px;
}

.cert-badge {
    display: flex;
    align-items: center;
    gap: 8px;
    font-size: 0.8rem;
    font-weight: 600;
    color: var(--theme-text-muted);
    background: var(--theme-bg-blue-light);
    padding: 6px 14px;
    border-radius: 50px;
    border: 1px solid var(--theme-bg-light);
    white-space: nowrap;
    box-shadow: 0 2px 5px var(--theme-shadow);
}

.cert-badge i {
    color: #FF6600;
    font-size: 0.9rem;
}

.cert-badge.google i {
    color: #4285F4;
}

/* Desktop Menu */
.nav-menu {
    display: flex;
    list-style: none;
    margin: 0;
    padding: 0;
    gap: 30px;
}

.nav-item {
    margin: 0;
}

.nav-link {
    color: var(--theme-nav-text);
    text-decoration: none;
    font-size: 0.95rem;
    font-weight: 500;
    transition: color 0.3s;
    position: relative;
}

.nav-link:hover {
    color: var(--theme-primary);
}

.nav-link::after {
    content: '';
    position: absolute;
    bottom: -5px;
    left: 0;
    width: 0;
    height: 2px;
    background: var(--theme-primary);
    transition: width 0.3s;
}

.nav-link:hover::after {
    width: 100%;
}

.nav-link.active {
    color: var(--theme-primary);
}

.nav-link.active::after {
    width: 100%;
    height: 1px;
}

/* Mobile Toggle Button */
.nav-toggle {
    display: none;
    flex-direction: column;
    justify-content: space-between;
    width: 28px;
    height: 20px;
    cursor: pointer;
    padding: 0;
    background: transparent;
    border: none;
    z-index: 10014;
    position: relative;
}

.bar {
    display: block;
    width: 100%;
    height: 2px;
    background: var(--theme-primary);
    border-radius: 1px;
    transition: all 0.3s;
}

.nav-toggle.active .bar:nth-child(1) {
    transform: rotate(45deg) translate(6px, 6px);
}

.nav-toggle.active .bar:nth-child(2) {
    opacity: 0;
}

.nav-toggle.active .bar:nth-child(3) {
    transform: rotate(-45deg) translate(6px, -6px);
}

/* Mobile Menu */
.nav-badges-mobile {
    display: none;
}

@media (max-width: 991px) {
    .nav-badges {
        display: none;
        /* On cache les badges sur tablette/mobile pour laisser de la place au menu */
    }
}

@media (max-width: 768px) {
    .nav-toggle {
        display: flex;
    }

    .nav-menu {
        position: fixed;
        top: 0;
        right: 0;
        width: 100%;
        height: 100vh;
        gap: 0;
        background: var(--theme-white);
        flex-direction: column;
        justify-content: flex-start;
        align-items: center;
        padding-top: 60px;
        padding-bottom: 100px;
        transform: translateX(100%);
        transition: transform 0.3s ease;
        box-shadow: -2px 0 10px var(--theme-shadow-dark);
        z-index: 10012;
        margin: 0;
        list-style: none;
        overflow-y: auto;
        overflow-x: hidden;
    }

    .nav-menu.active {
        transform: translateX(0);
    }

    .nav-item {
        margin: 0;
        padding: 0;
        width: 100%;
        border-bottom: 1px solid var(--theme-border);
    }

    .nav-item:first-child {
        border-top: 1px solid var(--theme-border);
    }

    .nav-link {
        display: block;
        padding: 20px 30px;
        font-size: 1.1rem;
        width: 100%;
        text-align: center;
        box-sizing: border-box;
    }

    .nav-link::after {
        display: none;
    }

    .nav-link:hover {
        background: #E8F1F8;
    }

    .nav-badges-mobile {
        display: flex;
        flex-direction: column;
        align-items: center;
        gap: 12px;
        margin-top: 30px;
        padding-bottom: 20px;
        width: 100%;
    }

    .nav-badges-mobile .cert-badge {
        background: #f8fbff;
        width: fit-content;
    }
}

/* Desktop padding */
@media (min-width: 769px) {
    .nav-container {
        padding: 15px 40px;
    }
}

@media (min-width: 1201px) {
    .nav-container {
        padding: 15px 80px;
    }
}

/* Dropdown Styles */
.dropdown {
    position: relative;
    cursor: pointer;
}

.dropdown-menu {
    display: none;
    position: absolute;
    top: 100%;
    left: 0;
    background-color: #ffffff;
    min-width: 220px;
    box-shadow: 0 8px 16px rgba(0, 0, 0, 0.1);
    z-index: 1000;
    list-style: none;
    padding: 10px 0;
    border-radius: 8px;
    border-top: 3px solid #FF6600;
}

.dropdown:hover .dropdown-menu {
    display: block;
    animation: fadeIn 0.3s ease;
}

.dropdown-menu li {
    padding: 0;
    width: 100%;
}

.dropdown-menu li a {
    color: #0A2342;
    padding: 12px 20px;
    text-decoration: none;
    display: block;
    font-size: 0.95rem;
    transition: background-color 0.2s, color 0.2s;
    text-align: left;
    border: none;
}

.dropdown-menu li a:hover {
    background-color: #f0f5fa;
    color: #FF6600;
    padding-left: 25px;
}

.dropdown-toggle i {
    font-size: 0.8em;
    margin-left: 5px;
    transition: transform 0.3s;
}

.dropdown:hover .dropdown-toggle i {
    transform: rotate(180deg);
}

@keyframes fadeIn {
    from {
        opacity: 0;
        transform: translateY(10px);
    }

    to {
        opacity: 1;
        transform: translateY(0);
    }
}

/* Mobile Dropdown */
@media (max-width: 768px) {
    .dropdown {
        width: 100%;
        display: block;
    }

    .dropdown-menu {
        position: static;
        box-shadow: none;
        background-color: #f9f9f9;
        width: 100%;
        display: none;
        padding-left: 0;
        border-top: none;
        border-left: 4px solid #FF6600;
        box-sizing: border-box;
    }

    .dropdown.active .dropdown-menu {
        display: block !important;
        animation: fadeIn 0.3s ease;
    }

    .dropdown:hover .dropdown-menu {
        display: none;
    }

    .dropdown.active:hover .dropdown-menu {
        display: block !important;
    }

    .dropdown-menu li a {
        padding: 15px 30px;
        text-align: center;
        border-bottom: 1px solid #eee;
    }

    .dropdown-toggle {
        width: 100%;
        display: flex !important;
        justify-content: center;
        align-items: center;
    }
}

