files.style.css:
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

html {
    overflow-x: hidden;
    overflow-y: auto;
    width: 100vw;
    max-width: 100vw;
    position: relative;
    margin: 0;
    padding: 0;
}

body {
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif !important;
    line-height: 1.6;
    overflow-x: hidden;
    overflow-y: visible;
    width: 100%;
    max-width: 100%;
    position: relative;
    margin: 0;
    padding: 0;
    min-width: 0;
}

/* Force all elements to respect viewport width */
*,
*::before,
*::after {
    max-width: 100%;
}

/* Prevent any element from causing horizontal scroll */
div,
p,
h1,
h2,
h3,
h4,
h5,
h6,
a,
span,
ul,
li {
    max-width: 100%;
    word-wrap: break-word;
    overflow-wrap: break-word;
}

/* Ensure sections don't overflow */
section {
    width: 100%;
    max-width: 100%;
    overflow-x: hidden;
    overflow-y: visible;
    box-sizing: border-box;
    position: relative;
    contain: layout style;
}

/* Ensure images don't overflow */
img {
    max-width: 100%;
    height: auto;
    display: block;
}

/* Scroll Animations */
.fade-in {
    opacity: 0;
    transform: translateY(30px);
    transition: all 0.6s ease-out;
}

.fade-in.visible {
    opacity: 1;
    transform: translateY(0);
}

.slide-in-left {
    opacity: 0;
    transform: translateX(-50px);
    transition: all 0.6s ease-out;
    will-change: transform, opacity;
    contain: layout style paint;
}

.slide-in-left.visible {
    opacity: 1;
    transform: translateX(0);
    will-change: auto;
}

.slide-in-right {
    opacity: 0;
    transform: translateX(50px);
    transition: all 0.6s ease-out;
    will-change: transform, opacity;
    contain: layout style paint;
}

.slide-in-right.visible {
    opacity: 1;
    transform: translateX(0);
    will-change: auto;
}

.scale-in {
    opacity: 0;
    transform: scale(0.8);
    transition: all 0.6s ease-out;
}

.scale-in.visible {
    opacity: 1;
    transform: scale(1);
}

/* Hero */
.hero {
    width: 100vw;
    max-width: 100vw;
    height: 95vh;
    background-image: linear-gradient(var(--theme-overlay), var(--theme-overlay)), url('image/Renovation-toiture-1.jpg');
    background-size: cover;
    background-position: center;
    background-repeat: no-repeat;
    display: flex;
    align-items: center;
    justify-content: center;
    position: relative;
    overflow-x: hidden;
    box-sizing: border-box;
}

.hero::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background-color: var(--theme-border-light);
    z-index: 1;
}

.hero-content {
    position: relative;
    z-index: 2;
}

.hero-content {
    text-align: center;
    color: var(--theme-white);
    max-width: 800px;
    padding: 0 20px;
}

.hero-title {
    font-size: 3.5rem;
    font-weight: 700;
    margin-bottom: 1.5rem;
    letter-spacing: 1px;
}

.hero-description {
    font-size: 1.25rem;
    font-weight: 300;
    margin-bottom: 2.5rem;
    line-height: 1.8;
    opacity: 0.95;
}

.hero-button {
    background-color: var(--theme-primary);
    color: var(--theme-white);
    font-size: 0.8rem;
    font-weight: 600;
    padding: 15px 40px;
    border: 2px solid var(--theme-primary);
    border-radius: 50px;
    cursor: pointer;
    transition: all 0.3s ease;
    text-transform: uppercase;
    letter-spacing: 1px;
    text-decoration: none;
    display: inline-block;
}

.hero-button:hover {
    background-color: var(--theme-primary-hover);
    border-color: var(--theme-primary-hover);
    color: var(--theme-white);
    transform: translateY(-3px);
    box-shadow: 0 10px 25px var(--theme-shadow-dark);
    text-decoration: none;
}

.hero-button:active {
    transform: translateY(-1px);
}

/* About Section */
.about-section {
    padding: 100px 20px;
    background-color: var(--theme-bg-light);
    width: 100%;
    max-width: 100%;
    overflow-x: hidden;
    overflow-y: visible;
    box-sizing: border-box;
    position: relative;
    contain: layout style;
}

.about-content {
    max-width: 1200px;
    margin: 0 auto;
    display: flex;
    align-items: center;
    gap: 60px;
    width: 100%;
    box-sizing: border-box;
}

.about-text {
    flex: 1;
}

.about-title {
