    margin-bottom: 2.5rem;
}

.stats {
    display: flex;
    gap: 40px;
    margin-bottom: 2.5rem;
}

.stat-item {
    text-align: left;
}

.stat-number {
    font-size: 3rem;
    font-weight: 700;
    color: #0A2342;
    margin-bottom: 0.5rem;
}

.stat-label {
    font-size: 1rem;
    color: #3E5066;
    line-height: 1.4;
}

.contact-button {
    background-color: var(--theme-primary);
    color: var(--theme-white);
    font-size: 1.1rem;
    font-weight: 600;
    padding: 15px 40px;
    border: none;
    border-radius: 50px;
    cursor: pointer;
    transition: all 0.3s ease;
    text-decoration: none;
    display: inline-block;
}

.contact-button:hover {
