    text-decoration: none;
}

.contact-button:active {
    transform: translateY(-1px);
}

.about-image {
    flex: 1;
    max-width: 500px;
}

.about-image img {
    width: 100%;
    max-width: 100%;
    height: auto;
    aspect-ratio: 1 / 1;
    object-fit: cover;
    border-radius: 10px;
    box-shadow: 0 10px 40px rgba(0, 0, 0, 0.15);
    display: block;
    box-sizing: border-box;
}

/* Services Section */
.services-section {
    padding: 100px 20px;
    background-color: var(--theme-white);
    width: 100vw;
    max-width: 100vw;
    overflow-x: hidden;
    overflow-y: visible;
