}

.intervention-title {
    font-size: 2.5rem;
    font-weight: 700;
    color: #05162B;
    margin-bottom: 20px;
}

.intervention-desc {
    font-size: 1.1rem;
    color: #3E5066;
    margin-bottom: 40px;
}

.intervention-list {
    display: flex;
    flex-wrap: wrap;
    justify-content: center;
    gap: 15px;
}

.city-badge {
    background-color: #ffffff;
    color: #05162B;
    padding: 12px 25px;
    border-radius: 50px;
    font-weight: 600;
    box-shadow: 0 4px 10px rgba(0, 0, 0, 0.05);
    border: 1px solid #e1e8f0;
    cursor: default;
    transition: all 0.3s ease;
}

.city-badge:hover {
    transform: translateY(-3px);
    box-shadow: 0 8px 20px rgba(0, 0, 0, 0.1);
    border-color: #FF6600;
    color: #FF6600;
}

@media (max-width: 768px) {
    .intervention-title {
        font-size: 2rem;
    }

    .intervention-list {
        gap: 10px;
    }

    .city-badge {
        padding: 10px 20px;
        font-size: 0.95rem;
    }
}

/* Local Gallery Styles */
.local-gallery-section {
    padding: 40px 20px 100px;
    background-color: #ffffff;
    width: 100%;
}

.local-gallery-container {
    max-width: 1200px;
    margin: 0 auto;
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 30px;
}

.gallery-item h3 {
    font-size: 1.8rem;
    color: #05162B;
    margin-bottom: 15px;
    font-weight: 700;
}

.gallery-item p {
    font-size: 1.1rem;
    color: #3E5066;
    line-height: 1.8;
    margin-bottom: 25px;
}

.gallery-img-wrapper {
    width: 100%;
    height: 400px;
    border-radius: 20px;
    overflow: hidden;
    box-shadow: 0 15px 45px rgba(0, 0, 0, 0.08);
    transition: transform 0.4s ease;
}

.gallery-img-wrapper img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    transition: transform 0.6s ease;
}

.gallery-item:hover .gallery-img-wrapper {
    transform: translateY(-8px);
}

.gallery-item:hover .gallery-img-wrapper img {
    transform: scale(1.05);
}

@media (max-width: 992px) {
    .local-gallery-container {
        grid-template-columns: 1fr;
        gap: 50px;
    }

    .gallery-img-wrapper {
        height: 350px;
    }
}

@media (max-width: 768px) {
    .local-gallery-section {
        padding: 20px 20px 60px;
    }

    .gallery-item h3 {
        font-size: 1.5rem;
    }
}
